/* ──────────────────────────────────────────────────────────────
   AnimatedEdge.tsx
   Custom edge that renders an animated dashed line with a
   directional arrow and a label showing connection type.
   ────────────────────────────────────────────────────────────── */
import React from 'react';
import { getBezierPath, EdgeProps, EdgeLabelRenderer } from 'react-flow-renderer';

export type ConnectionKind = 'data' | 'network' | 'replication' | 'event';

const KIND_COLORS: Record<ConnectionKind, string> = {
  data:        '#1e88e5',
  network:     '#43a047',
  replication: '#f4511e',
  event:       '#8e24aa',
};

const KIND_DASH: Record<ConnectionKind, string> = {
  data:        '5,0',       // solid
  network:     '8,4',       // dashed
  replication: '2,4',       // dotted
  event:       '10,4,2,4',  // dash-dot
};

export default function AnimatedEdge({
  id,
  sourceX,
  sourceY,
  targetX,
  targetY,
  sourcePosition,
  targetPosition,
  data,
  style = {},
  markerEnd,
}: EdgeProps) {
  const kind: ConnectionKind = (data?.kind as ConnectionKind) || 'data';
  const color = KIND_COLORS[kind];
  const dash = KIND_DASH[kind];
  const label: string = data?.label || kind;
  const bandwidth: string = data?.bandwidth || '';

  const [edgePath, labelX, labelY] = getBezierPath({
    sourceX,
    sourceY,
    sourcePosition,
    targetX,
    targetY,
    targetPosition,
  });

  return (
    <>
      {/* invisible wide path for easier selection */}
      <path
        id={`${id}-selector`}
        d={edgePath}
        fill="none"
        stroke="transparent"
        strokeWidth={20}
      />
      {/* visible animated path */}
      <path
        id={id}
        className="animated-edge-path"
        d={edgePath}
        fill="none"
        stroke={color}
        strokeWidth={2}
        strokeDasharray={dash}
        markerEnd={markerEnd}
        style={style}
      />
      {/* flow particles — SVG circles moving along the path */}
      <circle r={3} fill={color}>
        <animateMotion dur="2s" repeatCount="indefinite">
          <mpath xlinkHref={`#${id}`} />
        </animateMotion>
      </circle>
      <circle r={3} fill={color} opacity={0.5}>
        <animateMotion dur="2s" begin="1s" repeatCount="indefinite">
          <mpath xlinkHref={`#${id}`} />
        </animateMotion>
      </circle>

      {/* label */}
      <EdgeLabelRenderer>
        <div
          className="edge-label"
          style={{
            position: 'absolute',
            transform: `translate(-50%, -50%) translate(${labelX}px,${labelY}px)`,
            backgroundColor: color,
          }}
        >
          {label}
          {bandwidth && <span className="edge-bandwidth">{bandwidth}</span>}
        </div>
      </EdgeLabelRenderer>
    </>
  );
}
